#!/bin/bash\n\n# Nexus AI Project Setup Script\n# This script creates the complete project structure and files\n\necho \"🚀 Setting up Nexus AI Project...\"\n\n# Create directory structure\nmkdir -p frontend/src/{components,stores,services,hooks,types,app}\nmkdir -p backend/src/{controllers,middleware,routes,types}\nmkdir -p backend/prisma\nmkdir -p docs\nmkdir -p .github/workflows\n\necho \"✅ Directories created\"\n\n# Root Level Files\ncat > package.json << 'ROOTPKG'\n{\n  \"name\": \"nexus-ai\",\n  \"version\": \"1.0.0\",\n  \"description\": \"Advanced AI Chatbot Platform by W.A.I.T Tech\",\n  \"private\": true,\n  \"workspaces\": [\n    \"frontend\",\n    \"backend\"\n  ],\n  \"scripts\": {\n    \"dev\": \"concurrently \\\"npm run dev -w frontend\\\" \\\"npm run dev -w backend\\\"\",\n    \"build\": \"npm run build -w frontend && npm run build -w backend\",\n    \"start\": \"npm start -w backend\",\n    \"lint\": \"npm run lint -w frontend && npm run lint -w backend\",\n    \"type-check\": \"npm run type-check -w frontend && npm run type-check -w backend\"\n  },\n  \"devDependencies\": {\n    \"concurrently\": \"^8.2.1\"\n  }\n}\nROOTPKG\n\ncat > .gitignore << 'GITIGNORE'\nnode_modules/\n/.pnp\n.pnp.js\n/coverage\n/build\n/dist\n/.next\n/out\n.DS_Store\n*.pem\nnpm-debug.log*\nyarn-debug.log*\nyarn-error.log*\n.env\n.env.local\n.env.*.local\n.env.development.local\n.env.test.local\n.env.production.local\n.vscode/\n.idea/\n*.swp\n*.swo\n*~\nThumbs.db\n.prisma/\n.dockerignore\ndocker-compose.override.yml\nGITIGNORE\n\ncat > docker-compose.yml << 'DOCKER'\nversion: '3.8'\n\nservices:\n  postgres:\n    image: postgres:15-alpine\n    container_name: nexus-ai-db\n    environment:\n      POSTGRES_USER: nexus_user\n      POSTGRES_PASSWORD: nexus_password\n      POSTGRES_DB: nexus_ai\n    ports:\n      - \"5432:5432\"\n    volumes:\n      - postgres_data:/var/lib/postgresql/data\n    healthcheck:\n      test: [\"CMD-SHELL\", \"pg_isready -U nexus_user\"]\n      interval: 10s\n      timeout: 5s\n      retries: 5\n\n  backend:\n    build:\n      context: ./backend\n      dockerfile: Dockerfile\n    container_name: nexus-ai-backend\n    environment:\n      NODE_ENV: development\n      DATABASE_URL: postgresql://nexus_user:nexus_password@postgres:5432/nexus_ai\n      OPENAI_API_KEY: ${OPENAI_API_KEY}\n      JWT_SECRET: ${JWT_SECRET}\n      PORT: 5000\n    ports:\n      - \"5000:5000\"\n    depends_on:\n      postgres:\n        condition: service_healthy\n    volumes:\n      - ./backend:/app\n      - /app/node_modules\n\n  frontend:\n    build:\n      context: ./frontend\n      dockerfile: Dockerfile\n    container_name: nexus-ai-frontend\n    environment:\n      NEXT_PUBLIC_API_URL: http://localhost:5000\n    ports:\n      - \"3000:3000\"\n    depends_on:\n      - backend\n    volumes:\n      - ./frontend:/app\n      - /app/node_modules\n\nvolumes:\n  postgres_data:\n\nnetworks:\n  default:\n    name: nexus-ai-network\nDOCKER\n\necho \"✅ Root level files created\"\n\n# Frontend Files\ncat > frontend/package.json << 'FRONTPKG'\n{\n  \"name\": \"nexus-ai-frontend\",\n  \"version\": \"1.0.0\",\n  \"description\": \"Nexus AI Frontend Application\",\n  \"private\": true,\n  \"scripts\": {\n    \"dev\": \"next dev\",\n    \"build\": \"next build\",\n    \"start\": \"next start\",\n    \"lint\": \"next lint\",\n    \"type-check\": \"tsc --noEmit\"\n  },\n  \"dependencies\": {\n    \"react\": \"^18.2.0\",\n    \"react-dom\": \"^18.2.0\",\n    \"next\": \"^14.0.0\",\n    \"typescript\": \"^5.2.0\",\n    \"tailwindcss\": \"^3.3.0\",\n    \"zustand\": \"^4.4.0\",\n    \"axios\": \"^1.5.0\",\n    \"lucide-react\": \"^0.292.0\",\n    \"clsx\": \"^2.0.0\"\n  },\n  \"devDependencies\": {\n    \"@types/react\": \"^18.2.0\",\n    \"@types/node\": \"^20.0.0\",\n    \"postcss\": \"^8.4.30\",\n    \"autoprefixer\": \"^10.4.16\",\n    \"eslint\": \"^8.49.0\",\n    \"eslint-config-next\": \"^14.0.0\"\n  }\n}\nFRONTPKG\n\ncat > frontend/tsconfig.json << 'TSCONFIG'\n{\n  \"compilerOptions\": {\n    \"target\": \"ES2020\",\n    \"lib\": [\"ES2020\", \"DOM\", \"DOM.Iterable\"],\n    \"module\": \"ESNext\",\n    \"skipLibCheck\": true,\n    \"esModuleInterop\": true,\n    \"allowSyntheticDefaultImports\": true,\n    \"strict\": true,\n    \"jsx\": \"react-jsx\",\n    \"resolveJsonModule\": true,\n    \"allowJs\": true,\n    \"baseUrl\": \".\",\n    \"paths\": {\n      \"@/*\": [\"./src/*\"]\n    },\n    \"moduleResolution\": \"node\"\n  },\n  \"include\": [\"**/*.ts\", \"**/*.tsx\"],\n  \"exclude\": [\"node_modules\"]\n}\nTSCONFIG\n\ncat > frontend/tailwind.config.ts << 'TAILWIND'\nimport type { Config } from 'tailwindcss';\n\nconst config: Config = {\n  darkMode: 'class',\n  content: [\n    './src/**/*.{js,ts,jsx,tsx}',\n  ],\n  theme: {\n    extend: {\n      colors: {\n        primary: '#0066CC',\n        secondary: '#1A1A2E',\n        accent: '#00D4FF',\n        dark: '#0F0F1E',\n        light: '#F5F5F5',\n      },\n    },\n  },\n  plugins: [],\n};\n\nexport default config;\nTAILWIND\n\ncat > frontend/next.config.js << 'NEXTCONFIG'\n/** @type {import('next').NextConfig} */\nconst nextConfig = {\n  reactStrictMode: true,\n};\n\nmodule.exports = nextConfig;\nNEXTCONFIG\n\ncat > frontend/.env.example << 'ENVFRONT'\nNEXT_PUBLIC_API_URL=http://localhost:5000\nNEXT_PUBLIC_OPENAI_API_KEY=your_key_here\nENVFRONT\n\ncat > frontend/postcss.config.js << 'POSTCSS'\nmodule.exports = {\n  plugins: {\n    tailwindcss: {},\n    autoprefixer: {},\n  },\n};\nPOSTCSS\n\necho \"✅ Frontend configuration files created\"\n\n# Frontend Source Files\ncat > frontend/src/types/index.ts << 'TYPES'\nexport interface User {\n  id: string;\n  email: string;\n  username: string;\n  avatar?: string;\n  createdAt: Date;\n  updatedAt: Date;\n}\n\nexport interface Message {\n  id: string;\n  conversationId: string;\n  role: 'user' | 'assistant';\n  content: string;\n  createdAt: Date;\n  updatedAt: Date;\n}\n\nexport interface Conversation {\n  id: string;\n  userId: string;\n  title: string;\n  messages: Message[];\n  archived: boolean;\n  pinned: boolean;\n  createdAt: Date;\n  updatedAt: Date;\n}\nTYPES\n\ncat > frontend/src/stores/authStore.ts << 'AUTHSTORE'\nimport { create } from 'zustand';\nimport { User } from '@/types';\n\ninterface AuthState {\n  user: User | null;\n  isAuthenticated: boolean;\n  setUser: (user: User | null) => void;\n  logout: () => void;\n}\n\nexport const useAuthStore = create<AuthState>((set) => ({\n  user: null,\n  isAuthenticated: false,\n  setUser: (user) => set({ user, isAuthenticated: !!user }),\n  logout: () => set({ user: null, isAuthenticated: false }),\n}));\nAUTHSTORE\n\ncat > frontend/src/stores/chatStore.ts << 'CHATSTORE'\nimport { create } from 'zustand';\nimport { Conversation, Message } from '@/types';\n\ninterface ChatState {\n  conversations: Conversation[];\n  currentConversation: Conversation | null;\n  messages: Message[];\n  setConversations: (conversations: Conversation[]) => void;\n  setCurrentConversation: (conversation: Conversation | null) => void;\n  setMessages: (messages: Message[]) => void;\n  addMessage: (message: Message) => void;\n}\n\nexport const useChatStore = create<ChatState>((set) => ({\n  conversations: [],\n  currentConversation: null,\n  messages: [],\n  setConversations: (conversations) => set({ conversations }),\n  setCurrentConversation: (currentConversation) => set({ currentConversation }),\n  setMessages: (messages) => set({ messages }),\n  addMessage: (message) => set((state) => ({ messages: [...state.messages, message] })),\n}));\nCHATSTORE\n\necho \"✅ Frontend source files created\"\n\n# Backend Files\ncat > backend/package.json << 'BACKPKG'\n{\n  \"name\": \"nexus-ai-backend\",\n  \"version\": \"1.0.0\",\n  \"description\": \"Nexus AI Backend API\",\n  \"main\": \"dist/index.js\",\n  \"scripts\": {\n    \"dev\": \"ts-node-dev --respawn src/index.ts\",\n    \"build\": \"tsc\",\n    \"start\": \"node dist/index.js\"\n  },\n  \"dependencies\": {\n    \"express\": \"^4.18.2\",\n    \"@prisma/client\": \"^5.3.0\",\n    \"jsonwebtoken\": \"^9.1.0\",\n    \"bcryptjs\": \"^2.4.3\",\n    \"dotenv\": \"^16.3.1\",\n    \"cors\": \"^2.8.5\",\n    \"helmet\": \"^7.0.0\"\n  },\n  \"devDependencies\": {\n    \"typescript\": \"^5.2.0\",\n    \"@types/express\": \"^4.17.17\",\n    \"@types/node\": \"^20.0.0\",\n    \"ts-node-dev\": \"^2.0.0\",\n    \"ts-node\": \"^10.9.1\"\n  }\n}\nBACKPKG\n\ncat > backend/tsconfig.json << 'BACKTSCONFIG'\n{\n  \"compilerOptions\": {\n    \"target\": \"ES2020\",\n    \"module\": \"commonjs\",\n    \"lib\": [\"ES2020\"],\n    \"outDir\": \"./dist\",\n    \"rootDir\": \"./src\",\n    \"strict\": true,\n    \"esModuleInterop\": true,\n    \"skipLibCheck\": true,\n    \"forceConsistentCasingInFileNames\": true,\n    \"resolveJsonModule\": true,\n    \"baseUrl\": \".\",\n    \"paths\": {\n      \"@/*\": [\"./src/*\"]\n    }\n  },\n  \"include\": [\"src/**/*\"],\n  \"exclude\": [\"node_modules\", \"dist\"]\n}\nBACKTSCONFIG\n\ncat > backend/.env.example << 'ENVBACK'\nDATABASE_URL=postgresql://nexus_user:nexus_password@localhost:5432/nexus_ai\nOPENAI_API_KEY=your_openai_api_key\nJWT_SECRET=your_jwt_secret_key\nJWT_EXPIRE=7d\nNODE_ENV=development\nPORT=5000\nCORS_ORIGIN=http://localhost:3000\nENVBACK\n\ncat > backend/src/index.ts << 'BACKINDEX'\nimport express from 'express';\nimport cors from 'cors';\nimport helmet from 'helmet';\nimport dotenv from 'dotenv';\n\ndotenv.config();\n\nconst app = express();\nconst PORT = process.env.PORT || 5000;\n\napp.use(helmet());\napp.use(cors({ origin: process.env.CORS_ORIGIN || 'http://localhost:3000' }));\napp.use(express.json({ limit: '10mb' }));\n\napp.get('/api/health', (req, res) => {\n  res.json({ status: 'ok', message: 'Nexus AI Backend is running' });\n});\n\napp.listen(PORT, () => {\n  console.log(`🚀 Nexus AI Backend running on http://localhost:${PORT}`);\n});\nBACKINDEX\n\necho \"✅ Backend files created\"\n\n# Create remaining backend source files\ncat > backend/src/types/index.ts << 'BACKTYPES'\nexport interface User {\n  id: string;\n  email: string;\n  username: string;\n  passwordHash?: string;\n  createdAt: Date;\n  updatedAt: Date;\n}\n\nexport interface Conversation {\n  id: string;\n  userId: string;\n  title: string;\n  archived: boolean;\n  createdAt: Date;\n}\n\nexport interface APIResponse<T = any> {\n  success: boolean;\n  data?: T;\n  error?: string;\n}\nBACKTYPES\n\ncat > backend/src/middleware/auth.ts << 'AUTHMIDDLEWARE'\nimport { Request, Response, NextFunction } from 'express';\nimport jwt from 'jsonwebtoken';\n\nexport interface AuthRequest extends Request {\n  userId?: string;\n}\n\nexport const authMiddleware = (req: AuthRequest, res: Response, next: NextFunction) => {\n  try {\n    const token = req.headers.authorization?.replace('Bearer ', '');\n    if (!token) {\n      return res.status(401).json({ success: false, error: 'No token' });\n    }\n    const decoded = jwt.verify(token, process.env.JWT_SECRET || 'secret');\n    req.userId = (decoded as any).userId;\n    next();\n  } catch (error) {\n    res.status(401).json({ success: false, error: 'Invalid token' });\n  }\n};\nAUTHMIDDLEWARE\n\ncat > backend/prisma/schema.prisma << 'PRISMASCHEMA'\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id        String     @id @default(cuid())\n  email     String     @unique\n  username  String     @unique\n  passwordHash String?\n  conversations Conversation[]\n  createdAt DateTime   @default(now())\n  updatedAt DateTime   @updatedAt\n}\n\nmodel Conversation {\n  id        String     @id @default(cuid())\n  userId    String\n  user      User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title     String\n  messages  Message[]\n  archived  Boolean    @default(false)\n  createdAt DateTime   @default(now())\n  updatedAt DateTime   @updatedAt\n\n  @@index([userId])\n}\n\nmodel Message {\n  id            String   @id @default(cuid())\n  conversationId String\n  conversation  Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  role          String\n  content       String   @db.Text\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  @@index([conversationId])\n}\nPRISMASCHEMA\n\necho \"✅ Backend source files created\"\n\n# GitHub Actions\ncat > .github/workflows/ci.yml << 'GHACTION'\nname: CI\n\non:\n  push:\n    branches: [main]\n  pull_request:\n    branches: [main]\n\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - uses: actions/setup-node@v3\n        with:\n          node-version: '18'\n      - run: npm install\n      - run: npm run build\nGHACTION\n\necho \"✅ GitHub Actions workflow created\"\n\n# Documentation\ncat > docs/SETUP.md << 'SETUP'\n# Nexus AI Setup Guide\n\n## Prerequisites\n- Node.js 18+\n- PostgreSQL 14+\n- OpenAI API key\n\n## Quick Start\n\n### Backend\n```bash\ncd backend\nnpm install\ncp .env.example .env\n# Edit .env with your values\nnpx prisma generate\nnpx prisma migrate dev\nnpm run dev\n```\n\n### Frontend\n```bash\ncd frontend\nnpm install\ncp .env.example .env.local\n# Edit .env.local with your values\nnpm run dev\n```\n\n## Access\n- Frontend: http://localhost:3000\n- Backend: http://localhost:5000/api/health\n\n## Docker\n```bash\ndocker-compose up -d\n```\nSETUP\n\necho \"✅ Documentation created\"\n\necho \"\"\necho \"🎉 Nexus AI project structure created successfully!\"\necho \"\"\necho \"Next steps:\"\necho \"1. cd frontend && npm install && npm run dev\"\necho \"2. cd backend && npm install && npm run dev\"\necho \"\"\necho \"Don't forget to:\"\necho \"- Update backend/.env with your database URL and API keys\"\necho \"- Update frontend/.env.local with your API URL\"\necho \"- Run: npx prisma migrate dev (in backend directory)\"\necho \"\"\n